            const tmp = i;
            if (tmp >= 0) break :blk octaves + @as(usize, @intCast(tmp)) else break :blk octaves - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
        }).*.lacunarity = lacuna;
