pub fn createLandSpline(arg_ss: [*c]SplineStack, arg_f: f32, arg_g: f32, arg_h: f32, arg_i: f32, arg_j: f32, arg_k: f32, arg_bl: c_int) callconv(.C) [*c]Spline {
    var ss = arg_ss;
    _ = &ss;
    var f = arg_f;
    _ = &f;
