    addSplineVal(sp, -0.4000000059604645, sp3, 0.0);
    addSplineVal(sp, -0.3499999940395355, sp4, 0.0);
    addSplineVal(sp, -0.10000000149011612, sp5, 0.0);
    addSplineVal(sp, 0.20000000298023224, sp6, 0.0);
    if (bl != 0) {
