pub export fn getMineshafts(arg_mc: c_int, arg_seed: u64, arg_cx0: c_int, arg_cz0: c_int, arg_cx1: c_int, arg_cz1: c_int, arg_out: [*c]Pos, arg_nout: c_int) c_int {
