                                d = -i;
                            }
                            if (j > d) {
                                d = j;
                            }
                            if (-j > d) {
                                d = -j;
                            }
                            if ((d >= @as(c_int, 80)) or (nextInt(&s, @as(c_int, 80)) < d)) {
                                if ((out != null) and (n < nout)) {
