        },
        Mansion => {
            const sampleX = chunkX * 16 + 7;
            const sampleZ = chunkZ * 16 + 7;
            const id = getBiomeAt(g, 4, sampleX >> 2, 319 >> 2, sampleZ >> 2);
            return @intFromBool(id >= 0 and isViableFeatureBiome(g.*.mc, structureType, id) != 0);
        },
