pub export fn areBiomesViable(arg_g: [*c]const Generator, arg_x: c_int, arg_y: c_int, arg_z: c_int, arg_rad: c_int, arg_validB: u64, arg_validM: u64, arg_approx: c_int) c_int {
    const g = arg_g;
    const x = arg_x;
    var y = arg_y;
    const z = arg_z;
    const rad = arg_rad;
    const validB = arg_validB;
    const validM = arg_validM;
    const approx = arg_approx;

    const x1 = (x - rad) >> 2;
    const x2 = (x + rad) >> 2;
    const sx = x2 - x1 + 1;
    const z1 = (z - rad) >> 2;
    const z2 = (z + rad) >> 2;
    const sz = z2 - z1 + 1;

    y = (y - rad) >> 2;

    const corners = [_]Pos{
        .{ .x = x1, .z = z1 },
        .{ .x = x2, .z = z2 },
        .{ .x = x1, .z = z2 },
        .{ .x = x2, .z = z1 },
    };
    for (corners) |p| {
        const id = getBiomeAt(g, 4, p.x, y, p.z);
        if (id < 0 or id_matches(id, validB, validM) == 0) return 0;
    }
    if (approx >= 1) return 1;

    if (g.*.mc >= MC_1_18) {
        var i: c_int = 0;
        while (i < sx) : (i += 1) {
            var dat: u64 = 0;
            var j: c_int = 0;
            while (j < sz) : (j += 1) {
                const id = sampleBiomeNoise(@constCast(&g.*.unnamed_0.unnamed_1.bn), null, x1 + i, y, z1 + j, &dat, 0);
                if (id < 0 or id_matches(id, validB, validM) == 0) return 0;
            }
        }
        return 1;
    }

    const r = Range{
        .scale = 4,
        .x = x1,
        .z = z1,
        .sx = sx,
        .sz = sz,
        .y = y,
        .sy = 1,
    };
    const ids = allocCache(g, r);
    defer free(@as(?*anyopaque, @ptrCast(ids)));
    if (genBiomes(g, ids, r) != 0) return 0;

    var i: c_int = 0;
    while (i < sx * sz) : (i += 1) {
        const id = ids[@as(c_uint, @intCast(i))];
        if (id < 0 or id_matches(id, validB, validM) == 0) return 0;
    }
    return 1;
}
pub export fn isStrongholdBiome(arg_mc: c_int, arg_id: c_int) c_int {
