            @as(c_int, 1), @as(c_int, 14), @as(c_int, 19) => return @intFromBool(mc >= MC_1_7),
            @as(c_int, 6) => return @intFromBool(mc <= MC_1_6),
            @as(c_int, 7), @as(c_int, 11), @as(c_int, 16), @as(c_int, 26), @as(c_int, 134) => return 0,
            @as(c_int, 15) => return @intFromBool(mc >= MC_1_13),
            @as(c_int, 25) => return @intFromBool(mc <= MC_1_17),
            @as(c_int, 168), @as(c_int, 169) => return @intFromBool((mc <= MC_1_15) or (mc >= MC_1_18)),
            @as(c_int, 184), @as(c_int, 183) => return 0,
            else => return 1,
        }
        break;
    }
    return 0;
}
