pub export fn loadSavedSeeds(arg_fnam: [*c]const u8, arg_scnt: [*c]u64) [*c]u64 {
    var fnam = arg_fnam;
    _ = &fnam;
    var scnt = arg_scnt;
    _ = &scnt;
    var fp: [*c]FILE = fopen(fnam, "r");
    _ = &fp;
    var seed: u64 = undefined;
    _ = &seed;
    var i: u64 = undefined;
    _ = &i;
    var baseSeeds: [*c]u64 = undefined;
    _ = &baseSeeds;
    if (fp == @as([*c]FILE, @ptrCast(@alignCast(@as(?*anyopaque, @ptrFromInt(@as(c_int, 0))))))) return null;
    scnt.* = 0;
    while (!(feof(fp) != 0)) {
        if (fscanf(fp, "%ld", @as([*c]i64, @ptrCast(@alignCast(&seed)))) == @as(c_int, 1)) {
            scnt.* +%= 1;
        } else while (!(feof(fp) != 0) and (fgetc(fp) != @as(c_int, '\n'))) {}
    }
    if (scnt.* == @as(u64, @bitCast(@as(c_long, @as(c_int, 0))))) return null;
    baseSeeds = @as([*c]u64, @ptrCast(@alignCast(calloc(scnt.*, @sizeOf(u64)))));
    rewind(fp);
    {
        i = 0;
        while ((i < scnt.*) and !(feof(fp) != 0)) {
            if (fscanf(fp, "%ld", @as([*c]i64, @ptrCast(@alignCast(&baseSeeds[i])))) == @as(c_int, 1)) {
                i +%= 1;
            } else while (!(feof(fp) != 0) and (fgetc(fp) != @as(c_int, '\n'))) {}
        }
    }
    _ = fclose(fp);
    return baseSeeds;
}
