    const buf = std.mem.span(arg_buf);
    var lines = std.mem.tokenizeAny(u8, buf, "\r\n");
    var n: c_int = 0;

    while (lines.next()) |line_raw| {
        const line = std.mem.trim(u8, line_raw, " \t;");
        if (line.len == 0) continue;

        var name_buf: [64]u8 = [_]u8{0} ** 64;
        var name_len: usize = 0;
        var values: [4]c_int = .{ 0, 0, 0, 0 };
        var value_count: usize = 0;

        var i: usize = 0;
        while (i < line.len) : (i += 1) {
            const ch = line[i];
            if ((ch >= 'a' and ch <= 'z') or ch == '_') {
                if (name_len + 1 < name_buf.len) {
                    name_buf[name_len] = ch;
                    name_len += 1;
                }
            } else if (ch >= 'A' and ch <= 'Z') {
                if (name_len + 1 < name_buf.len) {
                    name_buf[name_len] = ch + 32;
                    name_len += 1;
                }
            }
        }

        var toks = std.mem.tokenizeAny(u8, line, " \t,;:");
        while (toks.next()) |tok| {
            if (value_count >= values.len) break;
            if (tok.len == 0) continue;

            if (tok[0] == '#') {
                const v = std.fmt.parseUnsigned(u32, tok[1..], 16) catch continue;
                values[value_count] = @as(c_int, @bitCast(v));
                value_count += 1;
            } else if (tok.len > 2 and tok[0] == '0' and (tok[1] == 'x' or tok[1] == 'X')) {
                const v = std.fmt.parseUnsigned(u32, tok[2..], 16) catch continue;
                values[value_count] = @as(c_int, @bitCast(v));
                value_count += 1;
            } else {
                const v = std.fmt.parseInt(c_int, tok, 10) catch continue;
                values[value_count] = v;
                value_count += 1;
            }
        }

        name_buf[name_len] = 0;
        var id: c_int = _str2id(@as([*c]u8, @ptrCast(&name_buf)));

        if (id >= 0 and id < 256) {
            if (value_count == 3) {
                const idx = @as(usize, @intCast(id));
                arg_biomeColors[idx][0] = @as(u8, @truncate(@as(u32, @bitCast(values[0] & 255))));
                arg_biomeColors[idx][1] = @as(u8, @truncate(@as(u32, @bitCast(values[1] & 255))));
                arg_biomeColors[idx][2] = @as(u8, @truncate(@as(u32, @bitCast(values[2] & 255))));
                n += 1;
            } else if (value_count == 1) {
                const idx = @as(usize, @intCast(id));
                const packed_color = values[0];
                arg_biomeColors[idx][0] = @as(u8, @truncate(@as(u32, @bitCast((packed_color >> 16) & 255))));
                arg_biomeColors[idx][1] = @as(u8, @truncate(@as(u32, @bitCast((packed_color >> 8) & 255))));
                arg_biomeColors[idx][2] = @as(u8, @truncate(@as(u32, @bitCast((packed_color >> 0) & 255))));
                n += 1;
            }
            continue;
        }

        if (value_count == 4) {
            id = values[0] & 255;
            if (id >= 0 and id < 256) {
                const idx = @as(usize, @intCast(id));
                arg_biomeColors[idx][0] = @as(u8, @truncate(@as(u32, @bitCast(values[1] & 255))));
                arg_biomeColors[idx][1] = @as(u8, @truncate(@as(u32, @bitCast(values[2] & 255))));
                arg_biomeColors[idx][2] = @as(u8, @truncate(@as(u32, @bitCast(values[3] & 255))));
                n += 1;
            }
        } else if (value_count == 2) {
            id = values[0] & 255;
            if (id >= 0 and id < 256) {
                const idx = @as(usize, @intCast(id));
                const packed_color = values[1];
                arg_biomeColors[idx][0] = @as(u8, @truncate(@as(u32, @bitCast((packed_color >> 16) & 255))));
                arg_biomeColors[idx][1] = @as(u8, @truncate(@as(u32, @bitCast((packed_color >> 8) & 255))));
                arg_biomeColors[idx][2] = @as(u8, @truncate(@as(u32, @bitCast((packed_color >> 0) & 255))));
                n += 1;
            }
        }
    }

    return n;
}
pub export fn biomesToImage(arg_pixels: [*c]u8, arg_biomeColors: [*c][3]u8, arg_biomes: [*c]const c_int, sx: c_uint, sy: c_uint, pixscale: c_uint, flip: c_int) c_int {
    var pixels = arg_pixels;
    _ = &pixels;
    var biomeColors = arg_biomeColors;
    _ = &biomeColors;
    var biomes = arg_biomes;
    _ = &biomes;
    _ = &sx;
    _ = &sy;
    _ = &pixscale;
    _ = &flip;
