                    _ = &id;
                    var r: c_uint = undefined;
                    _ = &r;
                    var g: c_uint = undefined;
                    _ = &g;
                    var b: c_uint = undefined;
                    _ = &b;
                    if ((id < @as(c_int, 0)) or (id >= @as(c_int, 256))) {
