                        r = @as(c_uint, @bitCast(@as(c_int, @bitCast(@as(c_uint, (blk: {
                            const tmp = id & @as(c_int, 127);
                            if (tmp >= 0) break :blk biomeColors + @as(usize, @intCast(tmp)) else break :blk biomeColors - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                        }).*[@as(c_uint, @intCast(@as(c_int, 0)))]))) - @as(c_int, 40)));
                        r = if (r > @as(c_uint, @bitCast(@as(c_int, 255)))) @as(c_uint, @bitCast(@as(c_int, 0))) else r & @as(c_uint, @bitCast(@as(c_int, 255)));
                        g = @as(c_uint, @bitCast(@as(c_int, @bitCast(@as(c_uint, (blk: {
                            const tmp = id & @as(c_int, 127);
                            if (tmp >= 0) break :blk biomeColors + @as(usize, @intCast(tmp)) else break :blk biomeColors - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                        }).*[@as(c_uint, @intCast(@as(c_int, 1)))]))) - @as(c_int, 40)));
                        g = if (g > @as(c_uint, @bitCast(@as(c_int, 255)))) @as(c_uint, @bitCast(@as(c_int, 0))) else g & @as(c_uint, @bitCast(@as(c_int, 255)));
                        b = @as(c_uint, @bitCast(@as(c_int, @bitCast(@as(c_uint, (blk: {
                            const tmp = id & @as(c_int, 127);
                            if (tmp >= 0) break :blk biomeColors + @as(usize, @intCast(tmp)) else break :blk biomeColors - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                        }).*[@as(c_uint, @intCast(@as(c_int, 2)))]))) - @as(c_int, 40)));
                        b = if (b > @as(c_uint, @bitCast(@as(c_int, 255)))) @as(c_uint, @bitCast(@as(c_int, 0))) else b & @as(c_uint, @bitCast(@as(c_int, 255)));
                    } else {
                        r = @as(c_uint, @bitCast(@as(c_uint, (blk: {
                            const tmp = id;
                            if (tmp >= 0) break :blk biomeColors + @as(usize, @intCast(tmp)) else break :blk biomeColors - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                        }).*[@as(c_uint, @intCast(@as(c_int, 0)))])));
                        g = @as(c_uint, @bitCast(@as(c_uint, (blk: {
                            const tmp = id;
                            if (tmp >= 0) break :blk biomeColors + @as(usize, @intCast(tmp)) else break :blk biomeColors - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                        }).*[@as(c_uint, @intCast(@as(c_int, 1)))])));
                        b = @as(c_uint, @bitCast(@as(c_uint, (blk: {
                            const tmp = id;
                            if (tmp >= 0) break :blk biomeColors + @as(usize, @intCast(tmp)) else break :blk biomeColors - ~@as(usize, @bitCast(@as(isize, @intCast(tmp)) +% -1));
                        }).*[@as(c_uint, @intCast(@as(c_int, 2)))])));
                    }
                    var m: c_uint = undefined;
                    _ = &m;
                    var n: c_uint = undefined;
                    _ = &n;
                    {
                        m = 0;
                        while (m < pixscale) : (m +%= 1) {
                            {
                                n = 0;
                                while (n < pixscale) : (n +%= 1) {
                                    var idx: c_int = @as(c_int, @bitCast((pixscale *% i) +% n));
                                    _ = &idx;
                                    if (flip != 0) {
                                        idx += @as(c_int, @bitCast((sx *% pixscale) *% ((pixscale *% j) +% m)));
                                    } else {
                                        idx += @as(c_int, @bitCast((sx *% pixscale) *% ((pixscale *% ((sy -% @as(c_uint, @bitCast(@as(c_int, 1)))) -% j)) +% m)));
                                    }
                                    var pix: [*c]u8 = pixels + @as(usize, @bitCast(@as(isize, @intCast(@as(c_int, 3) * idx))));
                                    _ = &pix;
                                    pix[@as(c_uint, @intCast(@as(c_int, 0)))] = @as(u8, @bitCast(@as(u8, @truncate(r))));
                                    pix[@as(c_uint, @intCast(@as(c_int, 1)))] = @as(u8, @bitCast(@as(u8, @truncate(g))));
                                    pix[@as(c_uint, @intCast(@as(c_int, 2)))] = @as(u8, @bitCast(@as(u8, @truncate(b))));
                                }
                            }
                        }
                    }
                }
            }
        }
    }
    return containsInvalidBiomes;
}
pub export fn savePPM(arg_path: [*c]const u8, arg_pixels: [*c]const u8, sx: c_uint, sy: c_uint) c_int {
    var path = arg_path;
    _ = &path;
    var pixels = arg_pixels;
    _ = &pixels;
    _ = &sx;
    _ = &sy;
    var fp: [*c]FILE = fopen(path, "wb");
    _ = &fp;
    if (!(fp != null)) return -@as(c_int, 1);
    _ = fprintf(fp, "P6\n%d %d\n255\n", sx, sy);
    var pixelsLen: usize = @as(usize, @bitCast(@as(c_ulong, (@as(c_uint, @bitCast(@as(c_int, 3))) *% sx) *% sy)));
    _ = &pixelsLen;
    var written: usize = fwrite(@as(?*const anyopaque, @ptrCast(pixels)), @sizeOf(u8), pixelsLen, fp);
    _ = &written;
    _ = fclose(fp);
    return @intFromBool(written != pixelsLen);
}
pub fn setColor(arg_colors: [*c][3]u8, arg_id: c_int, arg_hex: u32) callconv(.C) void {
    const idx: usize = if (arg_id >= 0)
        @as(usize, @intCast(arg_id))
    else
        ~@as(usize, @bitCast(@as(isize, @intCast(arg_id)) +% -1));
    arg_colors[idx][0] = @as(u8, @truncate((arg_hex >> 16) & 0xff));
    arg_colors[idx][1] = @as(u8, @truncate((arg_hex >> 8) & 0xff));
    arg_colors[idx][2] = @as(u8, @truncate((arg_hex >> 0) & 0xff));
}
pub fn _str2id(arg_s: [*c]const u8) callconv(.C) c_int {
    var s = arg_s;
    _ = &s;
    if (@as(c_int, @bitCast(@as(c_uint, s.*))) == @as(c_int, 0)) return -@as(c_int, 1);
    var f: [*c]const u8 = null;
    _ = &f;
    var ret: c_int = -@as(c_int, 1);
    _ = &ret;
    var id: c_int = undefined;
    _ = &id;
    {
        id = 0;
        while (id < @as(c_int, 256)) : (id += 1) {
            var p: [*c]const u8 = biome2str(MC_NEWEST, id);
            _ = &p;
            if ((p != null) and (!(f != null) or (strlen(f) < strlen(p)))) if (strstr(s, p) != null) {
                f = p;
                ret = id;
            };
            var t: [*c]const u8 = biome2str(MC_1_17, id);
            _ = &t;
            if (((t != null) and (t != p)) and (!(f != null) or (strlen(f) < strlen(t)))) if (strstr(s, t) != null) {
                f = t;
                ret = id;
            };
        }
    }
    return ret;
}
