}
pub export fn getRavinePos(arg_mc: c_int, arg_seed: u64, arg_x: c_int, arg_z: c_int, arg_g: [*c]const Generator, arg_ravine1: ?*StructureVariant, arg_ravine2: ?*StructureVariant) c_int {
    var mc = arg_mc;
    _ = &mc;
    var seed = arg_seed;
    _ = &seed;
    var x = arg_x;
    _ = &x;
    var z = arg_z;
