    var random_1: u64 = undefined;
    _ = &random_1;
    if (mc < MC_1_18) {
        var count: c_int = 0;
        _ = &count;
        {
            var i: c_int = 0;
            _ = &i;
            while (i < @as(c_int, 2)) : (i += 1) {
                setSeed(&random_1, (seed +% @as(u64, @bitCast(@as(c_long, @as(c_int, 1))))) -% @as(u64, @bitCast(@as(c_long, i))));
                setSeed(&random_1, ((@as(u64, @bitCast(@as(c_long, x))) *% nextLong(&random_1)) ^ (@as(u64, @bitCast(@as(c_long, z))) *% nextLong(&random_1))) ^ ((seed +% @as(u64, @bitCast(@as(c_long, @as(c_int, 1))))) -% @as(u64, @bitCast(@as(c_long, i)))));
                if ((@as(f64, @floatCast(nextFloat(&random_1))) >= 0.02) or ((count != 0) and (!(g != null) or !(isOceanic(getBiomeAt(g, @as(c_int, 1), @as(c_int, 16) * x, @as(c_int, 0), @as(c_int, 16) * z)) != 0)))) continue;
                var ravinePointer: ?*StructureVariant = if (count != 0) ravine2 else ravine1;
                _ = &ravinePointer;
                if (ravinePointer != null) {
                    ravinePointer.?.x = @as(i16, @bitCast(@as(c_short, @truncate((@as(c_int, 16) * x) + nextInt(&random_1, @as(c_int, 16))))));
                    var temp: c_int = nextInt(&random_1, @as(c_int, 40));
                    _ = &temp;
                    ravinePointer.?.y = @as(i16, @bitCast(@as(c_short, @truncate(@as(c_int, 20) + nextInt(&random_1, temp + @as(c_int, 8))))));
                    ravinePointer.?.z = @as(i16, @bitCast(@as(c_short, @truncate((@as(c_int, 16) * z) + nextInt(&random_1, @as(c_int, 16))))));
                    _ = nextFloat(&random_1);
                    _ = nextFloat(&random_1);
                    ravinePointer.?.size = @as(u8, @intFromFloat((@as(f32, @floatFromInt(@as(c_int, 4))) * nextFloat(&random_1)) + (@as(f32, @floatFromInt(@as(c_int, 2))) * nextFloat(&random_1))));
                }
                count += 1;
            }
        }
        return count;
    } else {
        setSeed(&random_1, seed +% @as(u64, @bitCast(@as(c_long, @as(c_int, 2)))));
        setSeed(&random_1, ((@as(u64, @bitCast(@as(c_long, x))) *% nextLong(&random_1)) ^ (@as(u64, @bitCast(@as(c_long, z))) *% nextLong(&random_1))) ^ (seed +% @as(u64, @bitCast(@as(c_long, @as(c_int, 2))))));
        if (@as(f64, @floatCast(nextFloat(&random_1))) >= 0.01) return 0;
        if (ravine1 != null) {
            ravine1.?.x = @as(i16, @bitCast(@as(c_short, @truncate((@as(c_int, 16) * x) + nextInt(&random_1, @as(c_int, 16))))));
            ravine1.?.y = @as(i16, @bitCast(@as(c_short, @truncate(@as(c_int, 10) + nextInt(&random_1, @as(c_int, 58))))));
            ravine1.?.z = @as(i16, @bitCast(@as(c_short, @truncate((@as(c_int, 16) * z) + nextInt(&random_1, @as(c_int, 16))))));
            _ = nextFloat(&random_1);
            _ = nextFloat(&random_1);
            ravine1.?.size = @as(u8, @intFromFloat((@as(f32, @floatFromInt(@as(c_int, 4))) * nextFloat(&random_1)) + (@as(f32, @floatFromInt(@as(c_int, 2))) * nextFloat(&random_1))));
        }
        return 1;
    }
    return 0;
